static int display_mode = 0;

if (ImGui::Begin("وضع العرض")) {
 ImGui::Text("طريقة العرض");
 ImGui::RadioButton("مضلل", &display_mode, 0);
 ImGui::SameLine();
 ImGui::RadioButton("سلكي", &display_mode, 1);
 ImGui::SameLine();
 ImGui::RadioButton("نقاط", &display_mode, 2);

 const char* mode_label = display_mode == 0 ? "مضلل" : (display_mode == 1 ? "سلكي" : "نقاط");
 ImGui::Text("الوضع الحالي: %s", mode_label);
}
ImGui::End();
